" DCL Object creation in Eclipse ADT:
" Right-click on package -> New -> Other ABAP Repository Object
" -> Core Data Services -> Access Control
" Name must match CDS view name exactly

" DCL syntax:
@MappingRole: true
define role ZCDS_MATERIAL_PLANT {
  grant select on ZCDS_MATERIAL_PLANT
    where (werks) = aspect pfcg_auth(
                      M_MATE_WRK, WERKS, ACTVT = '03'
                    );
}

" If DCL missing - symptom:
" SELECT FROM zcds_material_plant returns 0 rows
" No error message - just empty result
" SU53 may not show failure (no check was attempted)

" DCL with pfcg_auth - full example
@MappingRole: true
define role ZCDS_PLANT_MATERIAL {
  grant select on ZCDS_PLANT_MATERIAL
    where (werks) = aspect pfcg_auth(
      M_MATE_WRK,  " Authorization Object (from SU21)
      WERKS,       " Field in Authorization Object
      ACTVT = '03' " Activity: 03=Display
    );
}

" PFCG Role SU21 -> Authorization Object M_MATE_WRK:
" Fields: ACTVT, MATYPE, WERKS
" In PFCG -> Role -> Authorizations:
"   M_MATE_WRK:
"     ACTVT: 03
"     WERKS: 1000, 2000 (or * for all)
"     MATYPE: * (all)

" Multiple conditions in DCL:
define role ZCDS_SALES_VIEW {
  grant select on ZCDS_SALES_VIEW
    where (vkorg) = aspect pfcg_auth(V_VBAK_VKO, VKORG, ACTVT='03')
       or 1 = aspect pfcg_auth(V_VBAK_AAT, ACTVT='03');
}
